import { HttpErrorResponse } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { ApiService } from 'src/app/shared/services/api.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-user-gcc-ac-new',
  templateUrl: './user-gcc-ac-new.component.html',
  styleUrls: ['./user-gcc-ac-new.component.scss']
})
export class UserGccAcNewComponent implements OnInit {
  userGLForm: FormGroup;
  accountClassForm: FormGroup;
  loginUser: string;
  showList: boolean = false;
  enableButton: boolean = true;
  onbackSpace: boolean = false;
  userID: any;
  userName: any;
  usersList: any;
  permissionvalue: Array<any> = ['Allow', 'Disallow'];
  permissionvalue1: Array<any> = ['Allow', 'Disallow'];
  submit1: boolean = true;
  submit2: boolean = true;
  public userGLValues: Array<any> = [{
    permission: '',
    trnDesc: '',
    trnCode: ''
  }];

  public accClassDatas: Array<any> = [{
    permission: '',
    trnDesc: '',
    trnCode: ''
  }];
  permission: any;
  userGLResp: any;
  accountClassResp: any;
  submitBtn: boolean = false;
  editFlag: boolean = false;
  editAccFlag: boolean = false;
  submitAccBtn: boolean = false;
  allUserID: any;


  constructor(private formBuilder: FormBuilder, private apiService: ApiService, private toastService: ToastService) { }

  ngOnInit(): void {
    this.loginUser = localStorage.getItem('userFromLogin');

    this.userGLForm = this.formBuilder.group({
      userId: ["", Validators.required],
      permission: ["", Validators.required],
      userGLData: this.formBuilder.array([this.createuserGLDataGroup()])
    });

    this.accountClassForm = this.formBuilder.group({
      userId: ["", Validators.required],
      permission: ["", Validators.required],
      accountMaintenanceData: this.formBuilder.array([this.createaccountClassDataGroup()])
    });

    this.userGLForm.get('permission').patchValue('Allow');
    this.accountClassForm.get('permission').patchValue('Allow');

    this.getUserName();
  }

  
  private createuserGLDataGroup(): FormGroup {
    return new FormGroup({
      'trnDesc': new FormControl(''),
      'trnCode': new FormControl('')
    })
  }
  private createaccountClassDataGroup(): FormGroup {
    return new FormGroup({
      'trnDesc': new FormControl(''),
      'trnCode': new FormControl('')
    })
  }
  public adduserGLFormGroup() {
    const userGLData = this.userGLForm.get('userGLData') as FormArray
    userGLData.push(this.createuserGLDataGroup())
  }
  public addaccountClassFormGroup() {
    const accountMaintenanceData = this.accountClassForm.get('accountMaintenanceData') as FormArray
    accountMaintenanceData.push(this.createaccountClassDataGroup())
  }

  public removeuserGLData(i: number) {
    const userGLData = this.userGLForm.get('userGLData') as FormArray
      userGLData.removeAt(i)
  }
  public removeaccountClassData(i: number) {
    const accountMaintenanceData = this.accountClassForm.get('accountMaintenanceData') as FormArray
    accountMaintenanceData.removeAt(i)
  }

  getUserName() {
    this.apiService.getUserName().subscribe(userName => {
      this.userName = userName.sort();
      this.usersList = [];
      this.allUserID = this.userName;
      var list = document.getElementById('allusers');
      this.allUserID.forEach(function (item) {
        var option = document.createElement('option');
        option.value = item;
        list.appendChild(option);
      });
      if (this.userName) {
        console.log(this.userName);
      } else {
        console.log("No name");
      }
    });
  }
  keyPress(user: any) {
    if (user) {
      this.showList = true;
      let list = this.userName.filter(option => option.includes(user));
      this.usersList = list;
    }
    else {
      this.showList = false;
      this.usersList = [];
    }
  }
  onOptionsSelected(event) {
    this.userID = event.target.value;
    if (this.userID) {
      this.userGLForm.controls.userId.setValue(this.userID);
      this.showList = false;
      this.getGlTrndata();
      console.log(this.userID);
    }
  }

  resetAllTabs() {
    this.userGLForm.reset();
    this.accountClassForm.reset();

    this.userGLForm.get('permission').patchValue('Allow');
    this.accountClassForm.get('permission').patchValue('Allow');
  }

  keyUpevent(event) {
    if (event.keyCode === 8) {
      this.onbackSpace = true;
      this.showList = true;
      this.userGLForm.controls.permission.setValue('');
      this.accountClassForm.controls.permission.setValue('');
      this.permissionvalue = [''];
    }
    else {
      this.onbackSpace = false;
    }
  }
  getGlTrndata() {
    this.apiService.getUserIdGlData(this.userID).subscribe(trndata => {
      this.userGLValues = trndata
      if (this.userGLValues.length != 0) {
        this.permission = this.userGLValues[0].permission
        this.permissionGLData(this.permission)
      }
      else {
        this.permissionALL();
      }
    })
  }
  permissionGLData(permission) {
    this.permissionvalue = [permission];
    this.userGLForm.controls.permission.setValue(this.permission);

  }
  permissionALL() {
    this.permissionvalue = ['Allow', 'Disallow']
  }
  onaccountClassChange(event) {
    this.userID = event.target.value;
    if (this.userID) {
      this.accountClassForm.controls.userId.setValue(this.userID);
      this.showList = false;
      this.getAccDatata();
      console.log(this.userID);
    }
  }
  getAccDatata() {
    this.apiService.getUserIdAccData(this.userID).subscribe(accdata => {
      this.accClassDatas = accdata;
      console.log(this.accClassDatas);
      if (this.accClassDatas.length != 0) {
        this.permission = this.accClassDatas[0].permission;
        this.permissionAccData(this.permission);
      }
      else {
        this.permissionALL();
      }
    })
  }
  permissionAccData(permission) {
    this.permissionvalue = [permission];
    this.accountClassForm.controls.permission.setValue(this.permission);

  }

  onSubmitGlForm(userGLFormValue) {
    console.log("userGLFormValue", userGLFormValue);
    let userGlData = userGLFormValue.userGLData;
    console.log(userGlData);
  
    for (let i = 0; i < userGlData.length; i++) {
      for (let k = i + 1; k < userGlData.length; k++) {
          if (userGlData[i].trnCode != userGlData[k].trnCode) {
            console.log("not equal");
              //do stuff
        
    const userID = userGLFormValue.userId;
    const permission = userGLFormValue.permission;
    this.apiService.saveuserGlCode(userGlData, userID, permission).subscribe(savetrnres => {
      this.userGLResp = savetrnres;
      if (this.userGLResp == true) {
        this.submitBtn = true;
        this.editFlag = true;
        this.submit1 = false;
        // this.toastService.successMessage('Data Saved Successfully!.', '');
        Swal.fire({
          title: 'Record is Created',
          icon: 'success'
        });
        // this.userGLForm.reset();
      }
      else {
        // this.toastService.errorMessage('Failed to Save Data!', '');
        Swal.fire({
          title: 'Failed to Save Data.',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });
    }
    else{
      Swal.fire({
        text: 'GL code and GL code description should not be equal',
        icon: 'error'
      });
    }
  }
}


  }
  onSubmitAccountClassForm(accountClassForm) {
    console.log("accountClassForm", accountClassForm);
    let accountData = accountClassForm.accountMaintenanceData;
    for (let i = 0; i < accountData.length; i++) {
      for (let k = i + 1; k < accountData.length; k++) {
          if (accountData[i].trnCode != accountData[k].trnCode || accountData[i].trnDesc != accountData[k].trnDesc) {
            console.log("not equal");
    const userID = accountClassForm.userId;
    const permission = accountClassForm.permission;
    this.apiService.saveAccountClassCode(accountData, userID, permission).subscribe(saveaccresp => {
      this.accountClassResp = saveaccresp;
      if (this.accountClassResp == true) {

        this.submitAccBtn = true;
        this.editAccFlag = true;
        this.submit2 = false;
        // this.toastService.successMessage('Data Saved Successfully!.', '');
        Swal.fire({
          title: 'Record is Created',
          icon: 'success'
        });
        // this.accountClassForm.reset();
      }
      else {
        // this.toastService.errorMessage('Failed to Save Data!', '');
        Swal.fire({
          title: 'Failed to Save Data.',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });
    }
    else{
      Swal.fire({
        text: 'Account class and Account class description should not be equal',
        icon: 'error'
      });
    }
  }
}
    }


}
