import { Component, OnInit, QueryList, ViewChildren } from '@angular/core';
import { DataTableDirective } from 'angular-datatables';
import { Subject } from 'rxjs';
import { ApiService } from 'src/app/shared/services/api.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-global-gcc-ac-maintenance',
  templateUrl: './global-gcc-ac-maintenance.component.html',
  styleUrls: ['./global-gcc-ac-maintenance.component.scss']
})
export class GlobalGccAcMaintenanceComponent implements OnInit {
  udfFata: any;
  accClassData: any;
  UserId: any;
  gldeleteResponse: any;
  accResponse: any;
  dtOptions: DataTables.Settings[] = [];
  dtTrigger1: Subject<any> = new Subject<any>();
  dtTrigger2: Subject<any> = new Subject<any>();
  isLoading:boolean = false;
  isLoading2:boolean = false;
  udfData: any;
  @ViewChildren(DataTableDirective)
  dtElements: QueryList<DataTableDirective>;
  
  constructor(private apiService : ApiService,private toastService : ToastService) { }

  ngOnInit(): void {
    this.dtOptions[0]= {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [4] } ],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      retrieve:true
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };
    this.dtOptions[1]= {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [4] } ],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      retrieve:true
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };
    
  this.getUFDData();
  this.getAccdata();
  }

  displayToConsole(): void {
    this.dtElements.forEach((dtElement: DataTableDirective, index: number) => {
      dtElement.dtInstance.then((dtInstance: any) => {
        console.log(`The DataTable ${index} instance ID is: ${dtInstance.table().node().id}`);
      });
    });
  }

  ngOnDestroy(): void {
    this.dtTrigger1.unsubscribe();
    this.dtTrigger2.unsubscribe();
  }

  getUFDData() {
    this.isLoading = true;
    this.apiService.getGlData().subscribe(udfdata => {
      this.udfData = udfdata;
      console.log(this.udfData);
      console.log("this.udfData",this.udfData);
      this.isLoading = false;

      this.dtTrigger1.next();
    });
  }
  getAccdata() {
    this.isLoading2 = true;
    this.apiService.getAccData().subscribe(accdata => {
      this.accClassData = accdata;
      this.isLoading2 = false;
      
      this.dtTrigger2.next();
      console.log('GCC Data',this.accClassData);
    });
  }
  deleteGLData(row) {
    console.log(row);
    this.apiService.deleteGlData(row, this.UserId).subscribe(res => {
      this.gldeleteResponse = res;
      if(this.gldeleteResponse){
        Swal.fire({
          title: 'GL Code Record is Deleted',
          icon: 'success'
        });
        this.getUFDData();
      }
    });
  }
  deleteAccData(row) {
    this.apiService.deleteAcData(row, this.UserId).subscribe(res => {
      this.accResponse = res;
      if(this.accResponse){
        Swal.fire({
          title: 'Account Class Record is Deleted',
          icon: 'success'
        });
        this.getAccdata();
      }
    });
  }

}
