import { HttpErrorResponse } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { Observable, OperatorFunction } from 'rxjs';
import { debounceTime, distinctUntilChanged, map } from 'rxjs/operators';
import { ApiService } from 'src/app/shared/services/api.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';
@Component({
  selector: 'npr-transaction-code-new',
  templateUrl: './transaction-code-new.component.html',
  styleUrls: ['./transaction-code-new.component.scss']
})
export class TransactionCodeNewComponent implements OnInit {
  transactionCodeForm: FormGroup;
  showList: boolean = false;
  UserId: any;
  userName: any;
  usersList: any;
  currentUser: string;
  editFlag: boolean = false;
  showDelete: boolean = false;
  submitAccBtn: boolean = false;
  formValues: any;
  createrId: any;
  allUserID: any;
  constructor(private formBuilder: FormBuilder, private apiService: ApiService, private toastService: ToastService) { }

  ngOnInit(): void {
    this.currentUser = localStorage.getItem("userFromLogin");
    this.transactionCodeForm = this.formBuilder.group({
      userId: [""],
      creatorId: [""],
      transactionData: this.formBuilder.array([this.createtransactionCodeGroup()])
      // verifiedBy: [""],
      // verifiedTime: [""],
      // recordStatus: [""],
      // verifiedOnce: [""],
      // modNo: [""],
      // verifiedStatus: [""],
      // creatorDtStamp: [""],
    });
    this.getUserName();

  }

  private createtransactionCodeGroup(): FormGroup {
    return new FormGroup({
      'trnDesc': new FormControl(''),
      'trnCode': new FormControl('')
    })
  }
  
  public removeData(i: number) {
    const transactionData = this.transactionCodeForm.get('transactionData') as FormArray
    transactionData.removeAt(i)
  }

  public addFormGroup() {
    const transactionData = this.transactionCodeForm.get('transactionData') as FormArray
    transactionData.push(this.createtransactionCodeGroup())
  }

  getUserName() {
    this.apiService.getUserName().subscribe(userName => {
      this.userName = userName.sort();
      this.usersList = [];
      this.allUserID = this.userName;

      var list = document.getElementById('allusers');
      this.allUserID.forEach(function (item) {
        var option = document.createElement('option');
        option.value = item;
        list.appendChild(option);
      });
      console.log(list);
      if (this.userName) {
        console.log(this.userName);
      } else {
        console.log("No name");
      }
    });
  }
  // long id;
	// String trnCode;
	// String trnDesc;
	// String userId;
  onSubmit(transactionCodeForm) {
    this.formValues = transactionCodeForm.transactionData;
    this.createrId = transactionCodeForm.userId;
    console.log("transactionCodeForm",this.formValues, this.createrId,this.currentUser );
    
        this.apiService.saveTrnCode(this.formValues,
          this.createrId,this.currentUser).subscribe(res => {
            if (res == true) {
              this.submitAccBtn = true;
              // this.toastService.successMessage('Data Saved Successfully!.', '');
              Swal.fire({
                title: 'Record is Created',
                icon: 'success'
              });
              this.editFlag = true;
            }
            else {
              // this.toastService.errorMessage('Failed to Save Data!', '');
              Swal.fire({
                title: 'Failed to Save Data.',
                icon: 'error'
              });
            }
          },
            error => {
              if (HttpErrorResponse) {
                Swal.fire({
                  text: 'Server Error!',
                  icon: 'error'
                });
              }
            });

    
    
  }
}
export class TrnDataMaster {
  id;
  trnCode;
  trnDesc;
  userId;
  verifiedBy: string;
  verifiedTime: any;
  recordStatus: string;
  verifiedOnce: string;
  modNo: number;
  verifiedStatus: string;
  creatorDtStamp: any;
  creatorId: string;
}

